export const products = productList.map((item, index) => {

const name = item.replace(/-/g," ").replace(/\b\w/g,c=>c.toUpperCase());

const price = Math.floor(Math.random()*40000)+500;

const offer = Math.random()>0.5
? price - Math.floor(price*0.2)
: null;

return {
id:index+1,
name,
price,
offer,
image:`/products/${item}.jpg`,
description:`High quality ${name}`
};

});